"use client"
import React, { useState } from 'react'
import Link from 'next/link'
import { useRouter } from 'next/navigation'
import { useAuth } from '@/context/AuthContext'
import { validateLogin } from '@/lib/validation'
import { AuthFooter } from '@/component/auth/AuthLayout'
import { authApi } from '@/lib/api'
import { Eye, EyeOff, Loader2 } from 'lucide-react'
import Image from 'next/image'

const LoginPage = () => {
    const router = useRouter()
    const { login } = useAuth()

    const [email, setEmail] = useState('')
    const [password, setPassword] = useState('')
    const [showPassword, setShowPassword] = useState(false)
    const [errors, setErrors] = useState({})
    const [submitted, setSubmitted] = useState(false)
    const [loading, setLoading] = useState(false)

    const handleSubmit = async (e) => {
        e.preventDefault()
        setSubmitted(true)
        const errs = validateLogin(email, password)
        setErrors(errs)
        if (Object.keys(errs).length > 0) return

        setLoading(true)
        try {
            const { token, user } = await authApi.login(email, password)
            login(user, token)
            router.push('/')
        } catch (err) {
            setErrors({ api: err.message })
        } finally {
            setLoading(false)
        }
    }

    const e = (key) => submitted && errors[key]

    const inputBase = (hasError) =>
        `w-full px-4 py-3 rounded-xl text-[15px] outline-none transition-all duration-150 border ${
            hasError
                ? 'border-red-400 bg-red-50 focus:border-red-500 focus:ring-2 focus:ring-red-200'
                : 'border-[#dddfe2] bg-[#f5f6f7] focus:bg-white focus:border-[#1877f2] focus:ring-2 focus:ring-[#1877f2]/20'
        } text-[#1c1e21] placeholder-[#8a8d91]`

    return (
        <div className="min-h-screen bg-[#f0f2f5] flex flex-col">
            {/* Main content */}
            <div className="flex-1 flex flex-col lg:flex-row items-center justify-center px-4 py-8 gap-8 max-w-5xl mx-auto w-full">

                {/* Left — Branding */}
                <div className="flex flex-col items-center lg:items-start lg:flex-1 gap-4 lg:pb-16">
                    <div className="flex items-center gap-1">
                        <Image
                            src="/images/facebook-logo.jpg"
                            alt="Facebook"
                            width={52}
                            height={52}
                            className="rounded-full"
                        />
                        <span className="text-[#1877f2] text-5xl font-bold tracking-tight ml-1">facebook</span>
                    </div>
                    <p className="text-[#1c1e21] text-xl leading-relaxed text-center lg:text-left max-w-xs">
                        Connect with friends and the world around you on Facebook.
                    </p>
                </div>

                {/* Right — Login Card */}
                <div className="w-full max-w-99">
                    <div className="bg-white rounded-2xl p-4 shadow-elevated flex flex-col gap-3">
                        {/* API error */}
                        {errors.api && (
                            <div className="bg-red-50 border border-red-200 text-red-600 text-[13px] px-4 py-3 rounded-xl font-medium">
                                {errors.api}
                            </div>
                        )}

                        <form onSubmit={handleSubmit} noValidate className="flex flex-col gap-3">
                            {/* Email */}
                            <div>
                                <input
                                    type="text"
                                    placeholder="Email address or phone number"
                                    value={email}
                                    onChange={ev => setEmail(ev.target.value)}
                                    className={inputBase(e('email'))}
                                    autoComplete="email"
                                />
                                {e('email') && <p className="text-red-500 text-[12px] mt-1 px-1">{e('email')}</p>}
                            </div>

                            {/* Password */}
                            <div>
                                <div className="relative">
                                    <input
                                        type={showPassword ? 'text' : 'password'}
                                        placeholder="Password"
                                        value={password}
                                        onChange={ev => setPassword(ev.target.value)}
                                        className={inputBase(e('password')) + ' pr-12'}
                                        autoComplete="current-password"
                                    />
                                    <button
                                        type="button"
                                        onClick={() => setShowPassword(v => !v)}
                                        className="absolute right-3 top-1/2 -translate-y-1/2 text-[#8a8d91] hover:text-[#1c1e21] transition-colors p-1"
                                        tabIndex={-1}
                                    >
                                        {showPassword ? <EyeOff className="w-5 h-5" /> : <Eye className="w-5 h-5" />}
                                    </button>
                                </div>
                                {e('password') && <p className="text-red-500 text-[12px] mt-1 px-1">{e('password')}</p>}
                            </div>

                            {/* Submit */}
                            <button
                                type="submit"
                                disabled={loading}
                                className="w-full bg-[#1877f2] hover:bg-[#166fe5] active:bg-[#1464d8] disabled:opacity-60 disabled:cursor-not-allowed text-white font-bold py-3 rounded-xl text-[17px] transition-all duration-150 flex items-center justify-center gap-2 shadow-sm hover:shadow-md"
                            >
                                {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : 'Log in'}
                            </button>
                        </form>

                        {/* Forgot password */}
                        <div className="text-center">
                            <Link
                                href="/forgot-password"
                                className="text-[#1877f2] text-[14px] font-medium hover:underline"
                            >
                                Forgot password?
                            </Link>
                        </div>

                        {/* Divider */}
                        <div className="flex items-center gap-3 my-1">
                            <div className="flex-1 h-px bg-[#dddfe2]" />
                            <span className="text-[#8a8d91] text-[13px]">or</span>
                            <div className="flex-1 h-px bg-[#dddfe2]" />
                        </div>

                        {/* Create account */}
                        <div className="flex justify-center pb-1">
                            <Link
                                href="/signup"
                                className="bg-[#42b72a] hover:bg-[#36a420] active:bg-[#2d8f1c] text-white font-bold px-6 py-3 rounded-xl text-[15px] transition-all duration-150 shadow-sm hover:shadow-md"
                            >
                                Create new account
                            </Link>
                        </div>
                    </div>

                    <p className="text-center text-[13px] text-[#8a8d91] mt-5">
                        <span className="font-semibold text-[#1c1e21]">Create a Page</span>{' '}
                        for a celebrity, brand or business.
                    </p>
                </div>
            </div>

            <AuthFooter showLanguages />
        </div>
    )
}

export default LoginPage
